package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testParse() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat spyCsvFormat = mock(CSVFormat.class);
        CSVParser expectedParser = new CSVParser(new StringReader("test"), spyCsvFormat);

        // When
        CSVParser actualParser = csvFormat.parse(new StringReader("test"));

        // Then
        assertEquals(expectedParser.toString(), actualParser.toString());
    }
}
